void rgbToComponents_float(__global float *d_r, __global float *d_g, __global float *d_b,
                           unsigned char * src, int width, int height,
                           __global uchar *d_srcBuffer, cl_command_queue queue, cl_kernel kernel)
{
    int pixels = width*height;
    int alignedSize = ((width*height + THREADS - 1) / THREADS) * THREADS * 3;

    // Create buffer and copy host src to device buffer
    cl_int err;
    cl_mem d_src = clCreateBuffer(queue, CL_MEM_READ_ONLY | CL_MEM_COPY_HOST_PTR, pixels*3, src, &err);

    size_t globalWorkSize = alignedSize / 3;
    size_t localWorkSize = THREADS;

    err  = clSetKernelArg(kernel, 0, sizeof(cl_mem), &d_r);
    err |= clSetKernelArg(kernel, 1, sizeof(cl_mem), &d_g);
    err |= clSetKernelArg(kernel, 2, sizeof(cl_mem), &d_b);
    err |= clSetKernelArg(kernel, 3, sizeof(cl_mem), &d_src);
    err |= clSetKernelArg(kernel, 4, sizeof(int), &pixels);

    clEnqueueNDRangeKernel(queue, kernel, 1, NULL, &globalWorkSize, &localWorkSize, 0, NULL, NULL);
    clFinish(queue);

    clReleaseMemObject(d_src);
}

